# BEST PRACTICE: Task-aware gradient scaling with conflict detection
import torch
from torch import nn

class CricketMultiTaskOptimizer:
    """Production pattern: Monitor task gradient directions"""
    def __init__(self, model, task_names):
        self.model = model
        self.task_names = task_names
        self.grad_history = {t: [] for t in task_names}

    def compute_gradient_conflict(self):
        """Detect when tasks push shared encoder in opposite directions"""
        shared_grads = []
        for name, param in self.model.shared_encoder.named_parameters():
            if param.grad is not None:
                shared_grads.append(param.grad.view(-1))

        if len(shared_grads) < 2:
            return 0.0

        grad_concat = torch.cat(shared_grads)
        conflict = 1.0 - torch.nn.functional.cosine_similarity(
            grad_concat.unsqueeze(0),
            grad_concat.unsqueeze(0)
        ).mean()
        return conflict.item()

    def adaptive_loss_scaling(self, losses, conflict_threshold=0.3):
        """Scale losses inversely to conflict—reduce conflicting task weight"""
        conflict = self.compute_gradient_conflict()

        if conflict > conflict_threshold:
            # Dynamically reduce secondary task weight
            scaled_losses = losses.clone()
            scaled_losses[1:] *= (1.0 - conflict)
            return scaled_losses.sum()
        return sum(losses)

# ANTI-PATTERN: Naive equal weighting ignores task conflicts
class NaiveMultiTask(nn.Module):
    """DON'T DO THIS: No conflict awareness"""
    def forward(self, batch):
        # Simply adds losses without understanding task relationships
        loss_batting = self.batting_head(shared_features)
        loss_bowling = self.bowling_head(shared_features)
        return loss_batting + loss_bowling  # Unstable when tasks conflict!

